// ═══════════════════════════════════════════════════
// Reads active_trades.json written by MAIN workflow
// This is how Monitor knows what was bought today
// ═══════════════════════════════════════════════════
const fs = require('fs');
const path = require('path');
const STATE_FILE = path.join(process.env.HOME||'/root', 'autotrader', 'active_trades.json');
const today = new Date().toISOString().split('T')[0];

let state = null;
try {
  state = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8'));
} catch(e) {
  return [{ json: { skip: true, reason: 'No state file yet — MAIN workflow not run today', today } }];
}

// Skip if state is from a different day or session already closed
if (state.date !== today) {
  return [{ json: { skip: true, reason: 'State file is from ' + state.date + ' not today', today } }];
}
if (state.sessionClosed) {
  return [{ json: { skip: true, reason: 'Session already closed for today', today } }];
}

const openTrades = (state.trades||[]).filter(t => t.status === 'OPEN');
if (openTrades.length === 0) {
  return [{ json: { skip: true, reason: 'No open trades to monitor', today } }];
}

return [{ json: { ...state, openTrades, stateFile: STATE_FILE, skip: false } }];

// ═══════════════════════════════════════════════════
// Core monitor logic:
// 1. Compare live price vs target / stop-loss
// 2. Flag trades to exit
// 3. Check IST time for EOD squareoff (3:10 PM)
// 4. Update state file
// ═══════════════════════════════════════════════════
const fs = require('fs');
const data = items[0].json;
const liveData = data.data || {};
const openTrades = data.openTrades || [];
const STATE_FILE = data.stateFile;

// Current IST time
const now = new Date();
const istStr = now.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata', hour: 'numeric', minute: 'numeric', hour12: false });
const [istH, istM] = istStr.split(':').map(Number);
const isEOD = istH === 15 && istM >= 10;  // 3:10 PM or later
const timeStr = now.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' });

const toSell = [];    // trades that hit target or SL
const stillOpen = []; // trades still active
let totalPnL = 0;

for (const trade of openTrades) {
  const key = 'NSE:' + trade.symbol;
  const ltp = liveData[key]?.last_price || trade.entryPrice;
  const pnl = (ltp - trade.entryPrice) * trade.qty;
  const pnlPct = ((ltp - trade.entryPrice) / trade.entryPrice) * 100;
  totalPnL += pnl;

  const hitTarget = ltp >= trade.target;
  const hitSL     = ltp <= trade.stopLoss;
  const exitEOD   = isEOD;

  if (hitTarget || hitSL || exitEOD) {
    toSell.push({
      ...trade, ltp, pnl: +pnl.toFixed(2), pnlPct: +pnlPct.toFixed(2),
      exitReason: hitTarget ? 'TARGET_HIT' : hitSL ? 'STOPLOSS_HIT' : 'EOD_SQUAREOFF',
      exitTime: timeStr, status: 'CLOSING'
    });
  } else {
    stillOpen.push({ ...trade, ltp, pnl: +pnl.toFixed(2), pnlPct: +pnlPct.toFixed(2) });
  }
}

// All targets hit = session done early
const allTargetsHit = openTrades.length > 0 &&
  toSell.every(t => t.exitReason === 'TARGET_HIT') &&
  stillOpen.length === 0;

// Update state file
if (STATE_FILE) {
  try {
    const state = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8'));
    state.trades = [
      ...toSell.map(t => ({ ...t, status: 'CLOSED' })),
      ...stillOpen
    ];
    state.lastMonitorAt = now.toISOString();
    state.sessionClosed = isEOD || stillOpen.length === 0;
    state.totalPnL = +totalPnL.toFixed(2);
    fs.writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));
  } catch (e) { console.log('State update error:', e.message); }
}

return [{
  json: {
    ...data,
    toSell, stillOpen, totalPnL: +totalPnL.toFixed(2),
    hasExits: toSell.length > 0,
    allTargetsHit, isEOD, timeStr
  }
}];

const data = items[0].json;
const exits = data.toSell||[];
const still = data.stillOpen||[];
const emoji = r => r==='TARGET_HIT'?'🎯':r==='STOPLOSS_HIT'?'🛑':'⏰';
const exitLines = exits.map(t=>`${emoji(t.exitReason)} *${t.symbol}* — ${t.exitReason.replace('_',' ')}
   Entry:₹${t.entryPrice} Exit:₹${t.ltp} P&L:${t.pnl>=0?'+':''}₹${t.pnl}(${t.pnlPct>=0?'+':''}${t.pnlPct}%)`).join('
');
const openLines = still.length?'
⏳ Still open: '+still.map(t=>`${t.symbol}(₹${t.ltp} ${t.pnlPct>=0?'+':''}${t.pnlPct}%)`).join(', '):'
All positions closed.';
const totalStr = `Total P&L: ${data.totalPnL>=0?'+':''}₹${data.totalPnL}`;
const sessionMsg = data.allTargetsHit?'
🏆 ALL TARGETS HIT — Session complete! Great day!':''
const msg=`📊 *AUTO-TRADER EXIT*
${data.timeStr}
━━━━━━━━━━━━━━
${exitLines}
${openLines}
━━━━━━━━━━━━━━
${totalStr}${sessionMsg}`;
return[{json:{...data,exitMessage:msg}}];
